import { Link, useLocation } from 'react-router-dom';

const navLinks = [
  { label: 'Lab', path: '/' },
  { label: 'GoalOS', path: '/goalos' },
  { label: 'Founder', path: '/about' },
  { label: 'Waitlist', path: '/waitlist' },
];

export default function Navigation() {
  const location = useLocation();

  return (
    <header
      className="glass-nav"
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        zIndex: 500,
        padding: '0.75rem 2rem',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
      }}
    >
      {/* Logo */}
      <Link
        to="/"
        style={{ display: 'flex', alignItems: 'center', gap: '0.6rem', textDecoration: 'none' }}
        data-testid="nav-logo"
      >
        {/* Diamond icon */}
        <svg width="22" height="22" viewBox="0 0 22 22" fill="none">
          <rect
            x="11" y="1.5"
            width="12" height="12"
            rx="1.5"
            transform="rotate(45 11 1.5)"
            fill="white"
          />
        </svg>
        <div style={{ lineHeight: 1 }}>
          <div style={{ fontFamily: 'Outfit, sans-serif', fontWeight: 600, fontSize: '0.8rem', color: '#fff', letterSpacing: '-0.01em' }}>
            Goal Computing
          </div>
          <div style={{ fontFamily: 'Outfit, sans-serif', fontWeight: 300, fontSize: '0.6rem', color: '#71717a', letterSpacing: '0.15em', textTransform: 'uppercase' }}>
            Labs
          </div>
        </div>
      </Link>

      {/* Nav Links */}
      <nav style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
        {navLinks.map((link) => {
          const isActive = location.pathname === link.path;
          return (
            <Link
              key={link.path}
              to={link.path}
              className={`nav-pill ${isActive ? 'active' : ''}`}
              data-testid={`nav-${link.label.toLowerCase()}`}
            >
              {link.label}
            </Link>
          );
        })}
      </nav>
    </header>
  );
}
